var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 쌤 그럼 갑니다!","JPN":"それじゃ、先生、行きますよ！","ENG":"Here I come, Teach!","TWN":"老師，出發囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으리아야앗!","JPN":"うりゃああっ！","ENG":"Giddyup!","TWN":"啊噠啊噠啊噠！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으윽……!?","JPN":"ううっ……！？","ENG":"Ngh...?!","TWN":"呃呃……！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SMASH_ATTACK_SMALL"},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"서, 선생님 괜찮아요!?","JPN":"せ、先生、大丈夫ですか！？","ENG":"A-are you okay, Teach?!","TWN":"老…老師，你還好嗎！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괘, 괜찮아요. 아직 버틸만합니다.","JPN":"だ、大丈夫だよ。まだ行けそうだ。","ENG":"I-I’m fine, thank you. I can manage.","TWN":"沒…沒事，老師還挺得住！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 박스 군은 제 걱정은 말고 가위바위보에 집중해주세요. 이번 판에 무조건 이겨야만 하니까요!","JPN":"それより、ダンボール君は私の心配はいいから、じゃんけんに集中するんだ。今度こそ必ず勝たないと！","ENG":"Focus on winning rock paper scissors, Box. We must win at all cost!","TWN":"倒是紙箱小朋友，你還有餘力擔心我嗎？先專注在猜拳上吧。這一局非贏不可！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"안 그러면 우리 둘 다 바닷물에 입수하게 생겼으니까!","JPN":"負けたら、二人とも海に入ることになるぞ！","ENG":"Or else, we’re all going to get submerged underwater!","TWN":"否則我們二個都會被扔到水裡的！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으으, 근데 전 가위바위보 자신 없다고요…….","JPN":"うう、でも僕、じゃんけんは自信ないんですよ……","ENG":"Ugh, but I suck at rock paper scissors...","TWN":"嗚嗚，可是我對猜拳沒把握……"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하, 하하…… 리네도 참…….","JPN":"は、はは……マリちゃんったら……","ENG":"H-ha, ha ha... Rinae, you naughty girl...","TWN":"哈，哈哈……璃奈也真是的……"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"설마 선생님한테 상대로 말뚝박기를 제안할 줄이야…….","JPN":"まさか先生を相手に馬乗り遊びを提案するなんて……","ENG":"She suggested playing Johnny-on-a-Pony with Teacher...","TWN":"誰想得到她會跟老師說要玩騎馬打仗……"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"곤란하네…… 선생님께서 허리라도 다치시면 어떡하지……?","JPN":"困ったね……先生、腰でも痛めたらどうしよう……？","ENG":"I'm a bit worried... What if Teacher hurts his back...?","TWN":"真傷腦筋……萬一老師的腰傷到的話怎麼辦……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"안 할 거야……? 그래서?","JPN":"やめる……？　それじゃ？","ENG":"Not doing it...? So?","TWN":"我不玩……怎樣？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 그, 그건…….","JPN":"うん？　そ、それは……","ENG":"Hmm? W-well...","TWN":"嗯？那個……"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다들 뭐하는데!? 퍼뜩 온나!","JPN":"みんな、何やってんねん！？　はよ来てや！","ENG":"What are y’all doin’ over there? Come on!","TWN":"你們在幹啥！？還不快過來！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 나부터 할 게.","JPN":"じゃあ、私から行く。","ENG":"I’ll start first.","TWN":"那我先。"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보, 보라야……!?","JPN":"し、シホちゃん……！？","ENG":"B-Bora...?!","TWN":"寶…寶拉……！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보, 보라 양? 그렇게 갑자기 달려오시면……!","JPN":"し、シホ君？　そう急に走ってこられると……！","ENG":"B-Bora? Don’t run like that...!","TWN":"寶…寶拉？你這樣突然衝過來……！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SMASH_ATTACK_SMALL"},{"id":"L27_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으, 으으! 에잇……! 나도 모르겠다!","JPN":"う、うう！　ええいっ……！　もう私も知らない！","ENG":"U-ugh...! Here I go!","TWN":"呃呃呃！算了……！我不管了啦！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아! 여성팀의 승리래이! 쌤이랑 박스 입수 당첨~!","JPN":"わあ！　女性チームの勝利！　先生とダンボールは入水決定～！","ENG":"Whooo! It’s a victory for the ladies! Box and Teach, walk the plank!","TWN":"哇！女生隊獲勝！老師和紙箱下水～！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"마, 말도 안 돼! 이건 불공평해요!","JPN":"そ、そんな！　こんなの不公平です！","ENG":"N-no way! This is so unfair!","TWN":"怎…怎麼可能！不公平！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군 말이 맞습니다. 이쪽은 초등학생이 팀이고, 여성팀은 셋이죠. 처음부터 공정하지 못한 승부였습니다.","JPN":"そのとおり。こちらは小学生とチームで、女性チームは三人じゃないか。最初から公正ではない勝負だったぞ。","ENG":"He’s right. He’s an elementary student, while there are three of you. It wasn’t a fair game from the start.","TWN":"紙箱小朋友說的沒錯，我們這邊是小學生組合，你們女生隊有三個人，打從一開始就不是公平競爭。"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"변명이에요…… 그거.","JPN":"言い訳です……それ。","ENG":"An excuse... that is.","TWN":"根本就……輸不起。"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그, 그건…… 저희가 무겁다는 뜻인가요? 너무해요, 선생님!","JPN":"そ、それって……私たちが重いってことですか？　ひどいですよ、先生！","ENG":"D-does that mean... that we’re heavy? I’m offended, Teacher!","TWN":"老師的意思是……我們很胖嗎？老師你好過分！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 아니 그런 뜻이 아니라…… 하하.","JPN":"あ、いや、そういう意味では……はは。","ENG":"N-no, that's not what I meant... Ha ha.","TWN":"不是，老師不是那個意思……哈哈。"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"서, 선생님이 이렇게까지 당황하는 모습은 처음 봐.","JPN":"せ、先生がここまで慌ててるの初めて見たよ。","ENG":"I-I've never seen Teacher look so alarmed before.","TWN":"我…我還是第一次看到老師這麼驚慌。"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋아요, 쌤! 그럼 이번 판은 연습이라 치고, 다음은 저랑 팀 해요!","JPN":"わかりました、先生！　じゃあ、今のは練習ゲームってことで、次はウチとチームになりましょ！","ENG":"Alrighty, Teach! Let's consider this a practice round. This time, team up with me!","TWN":"好吧，老師！那這次就當作是練習，下一局我跟老師一隊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리, 리네야……! 진심이야!?","JPN":"ま、マリちゃん……！　本気！？","ENG":"R-Rinae... You can’t be serious!","TWN":"璃…璃奈……！你是說真的嗎！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"치사해……. 미리네.","JPN":"ずるい……マリ。","ENG":"Rinae... Not fair.","TWN":"好卑鄙……宓璃奈。"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 저는 좋습니다만…….","JPN":"ううむ、私はそれでもいいんだが……","ENG":"Hmm. I’m fine with it, but...","TWN":"嗯，我是很樂意啦……"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"리네 양은 괜찮겠어요? 세 명을 버텨야 할텐데요?","JPN":"マリ君は大丈夫なのかい？　三人分の体重に耐えないといけないんだよ？","ENG":"Will you be okay, Rinae? You’ll have to bear the weight of three people.","TWN":"但璃奈你沒關係嗎？對方有三個人喔？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥? 그게 무슨 소리에요, 선생님? 당연히 쌤이 말 역할이죠!","JPN":"ええっ？　何言ってるんですか、先生。当然先生が馬でしょ！","ENG":"Eh? What are you talking about, Teach? I thought it was obvious that you’re going to be the pony!","TWN":"嗯？什麼意思？當然是老師你要當馬囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어, 어떻게 해야 그런 결론이 나오는 거죠……?","JPN":"ど、どうしたらそのような結論が……？","ENG":"W-why on earth would that be obvious...?","TWN":"這…結論怎麼會是這樣……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 그렇다고 여자가 말뚝 박을 수는 없는 거잖아요?","JPN":"へへっ、だって女が馬になるわけにはいかないじゃないですか。","ENG":"Heh, ya wouldn’t make a lady be the pony, would you?","TWN":"嘿嘿，怎麼可以叫女生當馬呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으아 마…… 얼어 디질 뻔했다. 니들 너무 진심으로 하는 거 아이가?","JPN":"うわあ……凍え死ぬかと思うたわ。あんたたち、本気出しすぎやろ？","ENG":"Uah... I almost froze to death over there. Y’all were in it too deep.","TWN":"呃呃……差點就死咧，你們會不會玩得太認真啦？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이겨야지…… 게임이니까.","JPN":"勝たないと……ゲームだから。","ENG":"We have to win... It’s a game.","TWN":"玩遊戲……當然要贏。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"선생님, 여기 카레 냄비 근처에서 몸 말리세요. 수건 드릴까요?","JPN":"先生、このカレー鍋の近くで体を乾かしてください。タオル、いりますか？","ENG":"Here, Teacher. Warm yourself up near the curry pot. Do you need a towel?","TWN":"老師，你先在咖哩鍋這裡整理一下吧，需要毛巾嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하… 고맙습니다. 다인 양.","JPN":"はは……ありがとう。タエ君。","ENG":"Ha ha... Thank you, Dain.","TWN":"哈哈…謝謝你，妲茵。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 점심은 카레인가 보네요. 냄새가 달콤해서 좋군요…… ","JPN":"それより、お昼はカレーなんだね。甘くていい匂いが…… ","ENG":"I see we’re having curry for lunch. It smells very sweet...","TWN":"午餐是吃咖哩嗎？味道甜甜的很香呢……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 달콤?","JPN":"うむ？　甘い？","ENG":"Hmm? Sweet?","TWN":"嗯？甜甜的？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"넣었어요……. 초콜렛.","JPN":"入れました……チョコレート。","ENG":"Maple syrup… I put it in.","TWN":"有加……巧克力。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사과 주스…… 그리고 마시멜로우.","JPN":"リンゴジュース……それにマシュマロ。","ENG":"Apple juice... and marshmallows.","TWN":"蘋果汁……跟棉花糖。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보라 양, 레시피가 조금 이상하지 않습니까?","JPN":"シホ君、レシピが少しおかしくないかな？","ENG":"Don’t you think the recipe sounds rather peculiar, Bora?","TWN":"寶拉，你的食譜好像有點特別呢？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"맛있거든요…… 단 걸 많이 넣을 수록.","JPN":"おいしいんです……甘いもの、たくさん入れるほど。","ENG":"The better... the sweeter.","TWN":"好吃……越甜越好吃。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보라야! 아무리 그래도 내 카레에다가 그런 걸 말도 없이 넣으면 어떡해?","JPN":"シホちゃん！　いくらなんでも、何も言わずに私のカレーにそんなの入れちゃだめでしょ？","ENG":"Bora! How could you put all of that in without even asking?","TWN":"寶拉！你怎麼可以不說一聲，就把那些東西加到我的咖哩裡呢？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"맞아요! 저 다인 누나의 지극히 상식적인 카레를 기대하고 있었다고요!","JPN":"そうですよ！　僕、タエさんのごく常識的なカレーを楽しみにしてたんです！","ENG":"She’s right! I was hyped for Dain’s non-threatening curry!","TWN":"對啊！我很期待妲茵姊姊做的超正常咖哩欸！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스 군 말이 맞아! 생선 머리가 얼마나 몸에 좋고 맛도 좋은데!","JPN":"ダンボール君の言うとおりだよ！　魚の頭は身体にもいいし、おいしいんだから！","ENG":"Boxie is right! Fish heads are not only nutritious, but also delicious!","TWN":"紙箱小朋友說的沒錯！魚頭不只對身體好，味道也很棒！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그래요! 몸에 좋고, 맛도 좋은 생선 머리……?","JPN":"そうですよ！　身体にもいいし、美味しい魚の頭……？","ENG":"Yeah! Nutritious, and delicious fish... heads...?","TWN":"對啊！魚頭對身體好，味道又棒……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"바, 방금 생선 머리라고요!?","JPN":"い、今、魚の頭って言いました！？","ENG":"D-did you just say fish heads?!","TWN":"你…你剛說魚頭嗎！？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 왜 그래? 박스 군?","JPN":"うん？　どうしたの？　ダンボール君？","ENG":"Hmm? What’s wrong, Boxie?","TWN":"嗯？怎麼了嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어두육미라는 말도 있잖아?","JPN":"魚は頭が、獣は尻尾がおいしいって言葉もあるんだよ？","ENG":"You never heard of the old saying, \\"Head for fish, tail for meat\\"?","TWN":"人家不是說吃魚頭的人都很聰明嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사실, 생선 머리에는 다양한 영양소와 감칠 맛을 내는 성분이 들어 있거든. 그래서 옛 문헌에는 생선 머리를 이용한…….","JPN":"実は、魚の頭には様々な栄養素とコクを出す成分が入ってるの。それで、昔の文献には魚を頭を使った……","ENG":"Fish heads contain various nutritional components that bring out the savoriness of the dish. Back in the old days, fish heads were used to–","TWN":"魚頭呢，有豐富的營養，而且含有散發鮮味的成分，因此以前的文獻中，有許多針對魚頭的……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아니! 아무리 그래도 카레에 생선 머리는 아니잖아요!","JPN":"い、いや！　いくらなんでもカレーに魚の頭はないです！","ENG":"B-but still! Fish head curry is out of the question!","TWN":"等…等等！再怎麼說魚頭和咖哩也不搭吧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쯧쯧쯧. 다들 비키봐라. 내한텐 디진 요리도 되살리는 비장의 레시피가 있다 아이가!","JPN":"チッチッチッ。みんなどきいや。ウチには死んだ料理も甦らせる、とっておきのレシピがあるんや！","ENG":"Tsk, tsk. Move along, y’all. I have the ultimate ingredient that revives even the most revolting wretch!","TWN":"嘖嘖嘖，你們都給我走開！我有方法可以讓死亡料理起死回生唄！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그건…… 라면 스프!?","JPN":"そ、それは……ラーメンの粉末スープ！？","ENG":"Th-that’s... ramen powder!","TWN":"那…是…泡麵調味包！？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그만둬요, 미리네 누나! 이제와서 저 카레가 라면 스프 같은 걸로 되살아날 리 없잖아요!","JPN":"やめてください、マリさん！　いまさら粉末スープであのカレーが蘇るはずないじゃないですか！","ENG":"Stop it, Rinae! You can’t save that curry with regular ramen powder!","TWN":"快住手，宓璃奈姊姊！現在加入泡麵調味包也救不回那鍋咖哩啦！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라노! 라면 스프는 신이라고! 라면 스프가 살리지 못하는 음식 같은 건 없데이!","JPN":"何言ってるんや！　粉末スープは神様なんやで！　粉末スープに甦らせられない食べ物なんてない！","ENG":"Aah? Ya doubtin’ me, kiddo? Ramen powder is a cheat code! There ain’t nothin’ that a pack o’ ramen powder can’t fix!","TWN":"胡說！泡麵調味包就是神！沒有它救不回的料理！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L40_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"잔말 말고 내만 믿으라!","JPN":"黙っとき、ウチを信じろ！","ENG":"Trust me!","TWN":"廢話少說，聽我的準沒錯！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"음? 이거 생각보다 맛있는데?","JPN":"うん？　これ、思ったよりおいしいんやけど？","ENG":"Hmm? This ain’t bad at all!","TWN":"嗯？比想像中好吃欸？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스, 니도 이거 함 무봐라. 디진…… ","JPN":"ダンボール、あんたもちょっと食べてみいや。めっちゃ…… ","ENG":"Have a sip, Box. It's so–","TWN":"紙箱，你也吃吃看，有夠好……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쿠엑!?","JPN":"くへっ！？","ENG":"Kghh?!","TWN":"噁噁！？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리, 리네가 거품을 물었어! 구급차! 구급차를 불러야 해!","JPN":"ま、マリちゃんの口から泡が出てる！　救急車！　救急車を呼ばないと！","ENG":"R-Rinae’s foaming at the mouth! A-ambulance! Call an ambulance!","TWN":"璃… 璃奈口吐白沫！救護車！快叫救護車！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"결국, 여기까지 와서 컵라면이네요.","JPN":"結局、ここまで来てカップラーメンなんですね。","ENG":"So we came all the way here... only to end up with cup noodles.","TWN":"跑這麼遠來，結果還是吃泡麵。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나는 좀 괜찮아요?","JPN":"マリさんはもう大丈夫ですか？","ENG":"You okay, Rinae?","TWN":"姊姊你還好吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 괘안타. 괘안타. 원래 게임 개발은 열정, 헌신, 철야 그리고 컵라면이라 안 하나.","JPN":"へへっ、大丈夫。大丈夫やで。それに、ゲーム開発は情熱、献身、徹夜、そしてカップラーメンやからな。","ENG":"Heh, all's good. Game development really is about passion, all-nighters, and cup noodles after all.","TWN":"嘿嘿，沒事沒事，我不是說過，所謂的製作遊戲就是熱血、犧牲、熬夜、泡麵嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"방금 위세척까지 하고 온 사람이 그런 말을…….","JPN":"さっき胃洗浄までしてきた人がそんなこと言うなんて……","ENG":"You literally just went through stomach pumping...","TWN":"才剛洗完胃的人還敢說這種話……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하하, 누나는 정말로 긍정적이시네요. 부러울 정도로요.","JPN":"はは、マリさんは本当にポジティブなんですね。うらやましいくらいです。","ENG":"Ha ha, you really are optimistic, aren’t you? It’s amazing.","TWN":"哈哈，姊姊真的是很正面呢，正面到令人羨慕。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그에 비해서 저는…….","JPN":"それに比べて、僕は……","ENG":"I, on the other hand...","TWN":"跟你比起來我就……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스, 니 지금 내한테 칭찬한기가? 하핫, 뭔데? 내일 해는 서쪽에서 뜨는 거 아이가?","JPN":"ダンボール、あんた今ウチのこと褒めてんの？　ははっ、何や？　明日太陽は西から昇るんちゃう？","ENG":"Did you just compliment me, Box? Ha ha! What’s gotten into ya?","TWN":"紙箱，你剛是在誇獎我嗎？哈哈，怎麼搞的，明天太陽要打西邊出來啦？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네. 칭찬 맞아요. 고마워요, 누나.","JPN":"はい。褒めてます。ありがとうございます、マリさん。","ENG":"Yeah, I did. Thanks, Rinae.","TWN":"對，是誇獎沒錯，謝謝姊姊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"게임 같이 만들자고 해줘서. 그리고…… 저를 구해주셔서.","JPN":"ゲーム一緒に作ろうって言ってくれて。それに……僕を助けてくれて。","ENG":"For letting me join the team. And... for saving my life.","TWN":"謝謝你邀請我一起製作遊戲，還……救我一命。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내도 고맙데이.","JPN":"ウチもありがとな。","ENG":"It goes the same for me.","TWN":"我也要謝謝你。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스, 니 아니었으면, 결국 카운터즈 사가…… 끝까지 못 맹글었을끼다.","JPN":"ダンボール、あんたやなかったら、結局カウンターズ・サーガ……最後まで作れへんかったかも。","ENG":"If it wasn’t for ya, Box... Counters Saga would have never been finished.","TWN":"要不是你，制裁者傳奇……是不可能完成的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 그렇지! 내 좋은 생각 났다!","JPN":"あ、そうや！　ええこと思いついたわ！","ENG":"Oh, righty! I’ve got a great idea!","TWN":"這樣唄！我有個很棒的想法！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이번 코미페에서 우리 게임 대박나믄…… 오늘처럼 다같이 모여가 바다여행 한 번 더 오는기다.","JPN":"今度のコミフェでウチらのゲームが大ヒットしたら……今日みたいにみんなで集まってもっかい海に旅行に行こうや。","ENG":"If all goes well at Comic Festival... we’re gonna go to another vacation to the ocean.","TWN":"要是我們的遊戲在這次動漫展爆紅的話……那我們就像今天一樣，再一起去旅行吧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……좋아요. 대신 약속 하나 해요.","JPN":"……いいですよ。その代わり、一つだけ約束してください。","ENG":"…… All right. You have to promise me one thing, though.","TWN":"……好啊，但我有個條件，"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그 땐 컵라면 먹지 않기.","JPN":"その時はカップラーメン禁止。","ENG":"No more cup noodles.","TWN":"到時候不可以再讓我吃泡麵。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭔소리고! 그땐 여 말고 부산 앞바다로 온나! 그럼 내 풀코스로 모셔줄게!","JPN":"何言うてんねん！　その時にはここじゃなくてプサンの海に行くんやで！　フルコースでおもてなししてやるわ！","ENG":"Bet! Next time, we’re goin’ to Busan! Y’all are gettin’ a full-course meal from me!","TWN":"那還用說！到時候去我釜山的家！我請你吃全餐！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"푸흡……! 풀코스? 풀코스가 뭔데요?","JPN":"プフッ……！　フルコース？　フルコースって何ですか？","ENG":"Pfft...! Full course, you say? What does it include?","TWN":"噗哈……！全餐？全餐是什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와 웃는데? 그건 영업상 비밀이래이. 나중에 부산 오면 그때 알려줄게.","JPN":"なんで笑うん？　それは秘密やで。後でプサン来たら、その時に教えてあげるわ。","ENG":"What’s so funny, kiddo? The course... It’s a secret. You’ll know once we get there.","TWN":"笑啥笑？這是商業機密，等你來的時候再告訴你！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오늘따라 별이 참 이쁘네. 그쟈?","JPN":"今日は星がキレイやな。そう思わへん？","ENG":"Would ya look at that... Them stars are brighter than ever, don’t cha think so?","TWN":"今天的星空特別美呢，你說是唄？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와 말이 없노? 내만 그렇게 생각하나?","JPN":"なんで黙ってるん？　そう思うの、ウチだけか？","ENG":"Why are ya givin’ me the silent treatment again, kid? Can I get some support here?","TWN":"為啥不說話？你不覺得喔？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"정말 그렇네요. 예쁘네요. 별.","JPN":"本当にそうですね。綺麗です。星。","ENG":"You’re right. They’re beautiful... the stars.","TWN":"沒錯，星星真的很美。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};